import{_ as o,o as i,c as a,au as t}from"./chunks/framework.Bpqx6pAq.js";const f=JSON.parse('{"title":"Offline utilities","description":"","frontmatter":{},"headers":[],"relativePath":"api/map/utilities/utils.offline.md","filePath":"api/map/utilities/utils.offline.md"}'),c={name:"api/map/utilities/utils.offline.md"};function r(l,e,s,n,d,h){return i(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="offline-utilities" tabindex="-1">Offline utilities <a class="header-anchor" href="#offline-utilities" aria-label="Permalink to &quot;Offline utilities&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>This module provides functions for caching map views and their associated layers for offline use. It builds on the core KDK offline infrastructure and the <code>LocalCache</code> store to persist catalog, project, and feature data locally.</p><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="createofflineservicesforviews-offlinedocument" tabindex="-1"><code>createOfflineServicesForViews(offlineDocument)</code> <a class="header-anchor" href="#createofflineservicesforviews-offlinedocument" aria-label="Permalink to &quot;`createOfflineServicesForViews(offlineDocument)`&quot;">​</a></h3><p>Initialises offline-capable service instances for catalog, projects, and features data.</p><ul><li><strong>Parameters:</strong><ul><li><code>offlineDocument</code> <em>(Object)</em>: An offline document as produced by the core <code>createOfflineDocument</code> utility, containing a <code>metadata</code> object with service cache options.</li></ul></li><li><strong>Returns:</strong> <code>Promise&lt;void&gt;</code></li></ul><hr><h3 id="removeofflineservicesforviews" tabindex="-1"><code>removeOfflineServicesForViews()</code> <a class="header-anchor" href="#removeofflineservicesforviews" aria-label="Permalink to &quot;`removeOfflineServicesForViews()`&quot;">​</a></h3><p>Removes all offline service instances created for views and clears their cache entries.</p><ul><li><strong>Returns:</strong> <code>Promise&lt;void&gt;</code></li></ul><hr><h3 id="getofflinedocumentqueryforviews" tabindex="-1"><code>getOfflineDocumentQueryForViews()</code> <a class="header-anchor" href="#getofflinedocumentqueryforviews" aria-label="Permalink to &quot;`getOfflineDocumentQueryForViews()`&quot;">​</a></h3><p>Builds the query object required to populate an offline document for all cached views. Reads the cached views from <code>LocalCache</code> and constructs bounding-box queries for features.</p><ul><li><strong>Returns:</strong> <code>Promise&lt;Object&gt;</code> — An object with <code>catalog</code>, <code>projects</code>, and <code>features</code> query sub-objects.</li></ul><hr><h3 id="addviewtocache-view-options" tabindex="-1"><code>addViewToCache(view, options?)</code> <a class="header-anchor" href="#addviewtocache-view-options" aria-label="Permalink to &quot;`addViewToCache(view, options?)`&quot;">​</a></h3><p>Adds or updates a view entry in the <code>LocalCache</code> <code>&#39;views&#39;</code> store.</p><ul><li><strong>Parameters:</strong><ul><li><code>view</code> <em>(Object)</em>: The view (context) object to cache. Must have an <code>_id</code>.</li><li><code>options</code> <em>(Object, optional)</em>: Additional metadata to merge with the view entry (e.g. zoom bounds).</li></ul></li><li><strong>Returns:</strong> <code>Promise&lt;Object&gt;</code> — The updated views map.</li></ul><hr><h3 id="removeviewfromcache-view" tabindex="-1"><code>removeViewFromCache(view)</code> <a class="header-anchor" href="#removeviewfromcache-view" aria-label="Permalink to &quot;`removeViewFromCache(view)`&quot;">​</a></h3><p>Removes a view from the <code>LocalCache</code> <code>&#39;views&#39;</code> store.</p><ul><li><strong>Parameters:</strong><ul><li><code>view</code> <em>(Object)</em>: The view to remove. Must have an <code>_id</code>.</li></ul></li><li><strong>Returns:</strong> <code>Promise&lt;Object | undefined&gt;</code> — The removed view entry with its cached options, or <code>undefined</code> if it was not cached.</li></ul><hr><h3 id="cachelayersforview-view-layers-options" tabindex="-1"><code>cacheLayersForView(view, layers, options?)</code> <a class="header-anchor" href="#cachelayersforview-view-layers-options" aria-label="Permalink to &quot;`cacheLayersForView(view, layers, options?)`&quot;">​</a></h3><p>Caches all the given layers for the bounding box of the view.</p><ul><li><strong>Parameters:</strong><ul><li><code>view</code> <em>(Object)</em>: The view defining the bounding box (<code>south</code>, <code>west</code>, <code>north</code>, <code>east</code>).</li><li><code>layers</code> <em>(Array)</em>: The layers to cache.</li><li><code>options</code> <em>(Object, optional)</em>: Additional options forwarded to <code>setLayerCached</code> (e.g. <code>minZoom</code>, <code>maxZoom</code>).</li></ul></li><li><strong>Returns:</strong> <code>Promise&lt;void&gt;</code></li></ul><hr><h3 id="uncachelayersforview-view-layers-options" tabindex="-1"><code>uncacheLayersForView(view, layers, options?)</code> <a class="header-anchor" href="#uncachelayersforview-view-layers-options" aria-label="Permalink to &quot;`uncacheLayersForView(view, layers, options?)`&quot;">​</a></h3><p>Removes cached data for the given layers within the view bounding box.</p><ul><li><strong>Parameters:</strong><ul><li><code>view</code> <em>(Object)</em>: The view defining the bounding box.</li><li><code>layers</code> <em>(Array)</em>: The layers to uncache.</li><li><code>options</code> <em>(Object, optional)</em>: Additional options forwarded to <code>setLayerUncached</code>.</li></ul></li><li><strong>Returns:</strong> <code>Promise&lt;void&gt;</code></li></ul><hr><h3 id="cacheview-view-layers-options" tabindex="-1"><code>cacheView(view, layers, options?)</code> <a class="header-anchor" href="#cacheview-view-layers-options" aria-label="Permalink to &quot;`cacheView(view, layers, options?)`&quot;">​</a></h3><p>Performs a full view cache operation:</p><ol><li>Adds the view to the cache store.</li><li>Generates and populates an offline document for all cached views.</li><li>Creates offline service instances.</li><li>Caches the provided layers for the view&#39;s bounding box.</li></ol><ul><li><strong>Parameters:</strong><ul><li><code>view</code> <em>(Object)</em>: The view to cache.</li><li><code>layers</code> <em>(Array)</em>: The layers to cache for this view.</li><li><code>options</code> <em>(Object, optional)</em>: Additional options (e.g. <code>minZoom</code>, <code>maxZoom</code>).</li></ul></li><li><strong>Returns:</strong> <code>Promise&lt;void&gt;</code></li></ul><hr><h3 id="uncacheview-view-layers-options" tabindex="-1"><code>uncacheView(view, layers, options?)</code> <a class="header-anchor" href="#uncacheview-view-layers-options" aria-label="Permalink to &quot;`uncacheView(view, layers, options?)`&quot;">​</a></h3><p>Performs a full view uncache operation:</p><ol><li>Removes the view from the cache store.</li><li>Uncaches the provided layers.</li><li>When no more views remain in the cache, also removes offline services, the offline document, and the <code>&#39;views&#39;</code> and <code>&#39;services&#39;</code> cache entries.</li></ol><ul><li><strong>Parameters:</strong><ul><li><code>view</code> <em>(Object)</em>: The view to uncache. The stored options are merged back into <code>options</code>.</li><li><code>layers</code> <em>(Array)</em>: The layers to uncache.</li><li><code>options</code> <em>(Object, optional)</em>: Additional options forwarded to <code>uncacheLayersForView</code>.</li></ul></li><li><strong>Returns:</strong> <code>Promise&lt;void&gt;</code></li></ul>',41)])])}const m=o(c,[["render",r]]);export{f as __pageData,m as default};
